1	/* APL Environment styles */
2	
3	#main-content {
4	    flex: 1;
5	    display: flex;
6	    flex-direction: column;
7	    overflow: hidden;
8	    min-height: 0;
9	    position: relative;
10	}
11	
12	/* Control bar */
13	.control-bar {
14	    display: flex;
15	    align-items: center;
16	    gap: 8px;
17	    padding: 8px 16px;
18	    border-bottom: 1px solid var(--surface1);
19	    background: var(--mantle);
20	    flex-shrink: 0;
21	}
22	
23	.btn {
24	    font-family: var(--mono);
25	    font-size: 13px;
26	    padding: 4px 12px;
27	    border: 1px solid var(--surface2);
28	    border-radius: 4px;
29	    cursor: pointer;
30	    background: var(--surface0);
31	    color: var(--text);
32	    transition: background 0.15s;
33	}
34	
35	.btn:hover {
36	    background: var(--surface1);
37	}
38	
39	.btn-reset {
40	    color: var(--red);
41	    border-color: var(--red);
42	}
43	
44	.btn-upload {
45	    color: var(--blue);
46	    border-color: var(--blue);
47	}
48	
49	.demo-select {
50	    font-family: var(--mono);
51	    font-size: 12px;
52	    padding: 3px 6px;
53	    background: var(--surface0);
54	    color: var(--text);
55	    border: 1px solid var(--surface2);
56	    border-radius: 4px;
57	    cursor: pointer;
58	}
59	
60	/* REPL panel */
61	.repl-panel {
62	    flex: 1;
63	    display: flex;
64	    flex-direction: column;
65	    min-height: 0;
66	    outline: none;
67	    position: relative;
68	}
69	
70	.repl-panel:focus {
71	    outline: none;
72	}
73	
74	.repl-output {
75	    flex: 1;
76	    overflow-y: auto;
77	    padding: 12px 16px;
78	    background: var(--base);
79	    font-family: var(--mono);
80	    font-size: 15px;
81	    line-height: 1.5;
82	    color: var(--green);
83	    white-space: pre-wrap;
84	    word-break: break-all;
85	    scroll-behavior: smooth;
86	}
87	
88	.repl-line {
89	    min-height: 1.5em;
90	}
91	
92	.repl-input-line {
93	    display: inline;
94	}
95	
96	.repl-prompt {
97	    color: var(--blue);
98	}
99	
100	.repl-input-text {
101	    color: var(--text);
102	}
103	
104	.repl-cursor {
105	    color: var(--text);
106	    animation: cursor-blink 1.06s step-end infinite;
107	}
108	
109	/* Scroll-to-bottom indicator */
110	.scroll-to-bottom {
111	    position: absolute;
112	    bottom: 12px;
113	    left: 16px;
114	    font-family: var(--mono);
115	    font-size: 12px;
116	    padding: 4px 10px;
117	    border: 1px solid var(--surface2);
118	    border-radius: 4px;
119	    cursor: pointer;
120	    background: rgba(24, 24, 37, 0.9);
121	    color: var(--blue);
122	    z-index: 10;
123	}
124	
125	.scroll-to-bottom:hover {
126	    background: var(--surface0);
127	    color: var(--text);
128	}
129	
130	/* Hardware panel — floating bottom-right */
131	.hw-panel {
132	    position: absolute;
133	    bottom: 12px;
134	    right: 16px;
135	    background: rgba(24, 24, 37, 0.9);
136	    border: 1px solid var(--surface1);
137	    border-radius: 6px;
138	    padding: 10px 14px;
139	    font-family: var(--mono);
140	    font-size: 12px;
141	    color: var(--subtext0);
142	    z-index: 10;
143	    min-width: 140px;
144	}
145	
146	.hw-title {
147	    font-size: 11px;
148	    font-weight: 600;
149	    color: var(--overlay1);
150	    text-transform: uppercase;
151	    letter-spacing: 0.05em;
152	    margin-bottom: 8px;
153	}
154	
155	.hw-row {
156	    display: flex;
157	    align-items: center;
158	    gap: 8px;
159	    margin-bottom: 6px;
160	}
161	
