209	    background: var(--surface0);
210	    color: var(--overlay1);
211	    border: 1px solid var(--surface1);
212	}
213	
214	.hw-switch:hover {
215	    opacity: 0.85;
216	}
217	
218	.hw-byte {
219	    font-size: 12px;
220	    color: var(--text);
221	}
222	
223	/* Display mode toggle group */
224	.mode-group {
225	    display: inline-flex;
226	    gap: 0;
227	    margin-left: auto;
228	    margin-right: 80px;
229	}
230	
231	.btn-mode {
232	    border-radius: 0;
233	    border-right-width: 0;
