247	}
248	
249	.btn-mode-active {
250	    background: var(--mauve);
251	    color: var(--base);
252	    border-color: var(--mauve);
253	}
254	
255	/* APL keyword highlighting */
256	.apl-keyword {
257	    color: var(--mauve);
258	    font-weight: 600;
259	}
260	
261	/* Help button */
262	.btn-help {
263	    color: var(--yellow);
264	    border-color: var(--yellow);
265	    font-weight: 700;
266	    min-width: 28px;
267	    text-align: center;
268	}
269	
270	/* Index origin indicator */
271	.io-indicator {
272	    font-family: var(--mono);
273	    font-size: 11px;
274	    color: var(--teal);
275	    border: 1px solid var(--surface1);
276	    border-radius: 4px;
277	    padding: 2px 6px;
278	    white-space: nowrap;
279	    opacity: 0.8;
280	    user-select: none;
