/* APL Environment styles */

#main-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
    position: relative;
}

/* Control bar */
.control-bar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 16px;
    border-bottom: 1px solid var(--surface1);
    background: var(--mantle);
    flex-shrink: 0;
}

.btn {
    font-family: var(--mono);
    font-size: 13px;
    padding: 4px 12px;
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
    background: var(--surface0);
    color: var(--text);
    transition: background 0.15s;
}

.btn:hover {
    background: var(--surface1);
}

.btn-reset {
    color: var(--red);
    border-color: var(--red);
}

.btn-upload {
    color: var(--blue);
    border-color: var(--blue);
}

.demo-select {
    font-family: var(--mono);
    font-size: 12px;
    padding: 3px 6px;
    background: var(--surface0);
    color: var(--text);
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
}

/* REPL panel */
.repl-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    outline: none;
    position: relative;
}

.repl-panel:focus {
    outline: none;
}

.repl-output {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
    background: var(--base);
    font-family: var(--mono);
    font-size: 15px;
    line-height: 1.5;
    color: var(--green);
    white-space: pre-wrap;
    word-break: break-all;
    scroll-behavior: smooth;
}

.repl-line {
    min-height: 1.5em;
}

.repl-input-line {
    display: inline;
}

.repl-prompt {
    color: var(--blue);
}

.repl-input-text {
    color: var(--text);
}

.repl-cursor {
    color: var(--text);
    animation: cursor-blink 1.06s step-end infinite;
}

/* Scroll-to-bottom indicator */
.scroll-to-bottom {
    position: absolute;
    bottom: 12px;
    left: 16px;
    font-family: var(--mono);
    font-size: 12px;
    padding: 4px 10px;
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
    background: rgba(24, 24, 37, 0.9);
    color: var(--blue);
    z-index: 10;
}

.scroll-to-bottom:hover {
    background: var(--surface0);
    color: var(--text);
}

/* Hardware panel — floating bottom-right */
.hw-panel {
    position: absolute;
    bottom: 12px;
    right: 16px;
    background: rgba(24, 24, 37, 0.9);
    border: 1px solid var(--surface1);
    border-radius: 6px;
    padding: 10px 14px;
    font-family: var(--mono);
    font-size: 12px;
    color: var(--subtext0);
    z-index: 10;
    min-width: 140px;
}

.hw-title {
    font-size: 11px;
    font-weight: 600;
    color: var(--overlay1);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 8px;
}

.hw-row {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 6px;
}

.hw-row:last-child {
    margin-bottom: 0;
}

.hw-label {
    color: var(--overlay2);
    min-width: 20px;
}

.hw-label-rx {
    margin-left: 8px;
}

/* D2 LED */
.hw-led {
    width: 12px;
    height: 12px;
    border-radius: 50%;
    display: inline-block;
}

.hw-led-on {
    background: var(--green);
    box-shadow: 0 0 6px var(--green);
}

.hw-led-off {
    background: var(--surface0);
    border: 1px solid var(--surface1);
}

/* S2 switch */
.hw-switch {
    padding: 2px 8px;
    border-radius: 3px;
    cursor: pointer;
    font-size: 11px;
    font-weight: 600;
    user-select: none;
}

.hw-switch-on {
    background: var(--blue);
    color: var(--base);
}

.hw-switch-off {
    background: var(--surface0);
    color: var(--overlay1);
    border: 1px solid var(--surface1);
}

.hw-switch:hover {
    opacity: 0.85;
}

.hw-byte {
    font-size: 12px;
    color: var(--text);
}

/* Display mode toggle group */
.mode-group {
    display: inline-flex;
    gap: 0;
    margin-left: auto;
