    font-size: 12px;
    color: var(--mauve);
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

.help-key {
    white-space: nowrap;
    color: var(--green);
    min-width: 80px;
}

.help-intro {
    font-family: var(--mono);
    font-size: 12px;
    color: var(--subtext0);
    margin: 0 0 12px 0;
    line-height: 1.5;
}

.help-em {
    color: var(--text);
    font-weight: 600;
}

.help-col-header td {
    font-size: 11px;
    color: var(--overlay1);
    text-transform: uppercase;
    letter-spacing: 0.04em;
    padding-bottom: 4px;
}

.help-kw-table {
    margin-bottom: 4px;
}

.help-glyph {
    color: var(--mauve);
    white-space: nowrap;
