.help-note {
    padding-top: 8px;
    font-style: italic;
    color: var(--subtext0);
    font-size: 12px;
}

/* Cursor blink animation */
@keyframes cursor-blink {
    0%, 49% { opacity: 1; }
    50%, 100% { opacity: 0; }
}

/* Responsive: narrow viewports */
@media (max-width: 600px) {
    .control-bar {
        flex-wrap: wrap;
        padding: 6px 10px;
        gap: 6px;
    }

    .hw-panel {
        position: static;
        margin: 0 10px 8px;
        border-radius: 4px;
    }

    .repl-output {
        padding: 8px 10px;
        font-size: 13px;
    }
}

@media (max-width: 400px) {
    .btn {
        font-size: 12px;
        padding: 3px 8px;
    }

    .demo-select {
        font-size: 11px;
        width: 100%;
    }
}

