1	//! APL glyph prettification — maps ASCII keywords to APL symbols or literate names.
2	
3	/// Display mode for APL output.
4	#[derive(Clone, Copy, Debug, PartialEq, Default)]
5	pub enum DisplayMode {
6	    /// Show raw ASCII source (`rho`, `iota`, etc.)
7	    #[default]
8	    Repr,
9	    /// Show APL glyphs (`⍴`, `⍳`, `↑`, `↓`)
10	    Glyph,
11	    /// Show literate English names (`shape-of`, `index-gen`, etc.)
12	    Literate,
13	}
14	
15	/// A segment of prettified output.
16	#[derive(Clone, Debug)]
17	pub enum Segment {
18	    /// Plain text, not a keyword.
19	    Plain(String),
20	    /// A keyword that was transformed.
21	    Keyword(String),
22	}
23	
24	pub struct KeywordEntry {
25	    pub ascii: &'static str,
26	    pub glyph: &'static str,
27	    /// Literate name when used monadically (prefix): `rho X` → "shape-of"
28	    pub literate_monadic: &'static str,
29	    /// Literate name when used dyadically (infix): `A rho B` → "reshape".
30	    /// `None` means the keyword is always monadic.
31	    pub literate_dyadic: Option<&'static str>,
32	}
33	
34	pub const KEYWORDS: &[KeywordEntry] = &[
35	    KeywordEntry {
36	        ascii: "rho",
37	        glyph: "\u{2374}", // ⍴
38	        literate_monadic: "shape-of",
39	        literate_dyadic: Some("reshape"),
40	    },
41	    KeywordEntry {
42	        ascii: "iota",
43	        glyph: "\u{2373}", // ⍳
44	        literate_monadic: "index-gen",
45	        literate_dyadic: None,
46	    },
47	    KeywordEntry {
48	        ascii: "take",
49	        glyph: "\u{2191}", // ↑
50	        literate_monadic: "take",
51	        literate_dyadic: None,
52	    },
53	    KeywordEntry {
54	        ascii: "drop",
55	        glyph: "\u{2193}", // ↓
56	        literate_monadic: "drop",
57	        literate_dyadic: None,
58	    },
59	    KeywordEntry {
60	        ascii: "qled",
61	        glyph: "\u{2395}LED", // ⎕LED
62	        literate_monadic: "LED",
63	        literate_dyadic: None,
64	    },
65	    KeywordEntry {
66	        ascii: "qsw",
67	        glyph: "\u{2395}SW", // ⎕SW
68	        literate_monadic: "switch",
69	        literate_dyadic: None,
70	    },
71	    KeywordEntry {
72	        ascii: "qsvo",
73	        glyph: "\u{2395}SVO", // ⎕SVO
74	        literate_monadic: "share",
75	        literate_dyadic: Some("share"),
76	    },
77	    KeywordEntry {
78	        ascii: "rev",
79	        glyph: "\u{233D}", // ⌽
80	        literate_monadic: "reverse",
81	        literate_dyadic: None,
82	    },
83	    KeywordEntry {
84	        ascii: "cat",
85	        glyph: "\u{002C}", // ,
86	        literate_monadic: "ravel",
87	        literate_dyadic: Some("catenate"),
88	    },
89	    KeywordEntry {
90	        ascii: "and",
91	        glyph: "\u{2227}", // ∧
92	        literate_monadic: "and",
93	        literate_dyadic: None,
94	    },
95	    KeywordEntry {
96	        ascii: "or",
97	        glyph: "\u{2228}", // ∨
98	        literate_monadic: "or",
99	        literate_dyadic: None,
100	    },
101	    KeywordEntry {
102	        ascii: "not",
103	        glyph: "\u{223C}", // ∼
104	        literate_monadic: "complement",
105	        literate_dyadic: None,
106	    },
107	    KeywordEntry {
108	        ascii: "goto",
109	        glyph: "\u{2192}", // →
110	        literate_monadic: "branch",
111	        literate_dyadic: None,
112	    },
113	];
114	
115	/// Prettify a line according to the display mode.
116	///
117	/// Returns a list of segments: `Plain` for non-keyword text, `Keyword` for
118	/// transformed keywords. In `Repr` mode, returns a single `Plain` segment.
119	pub fn prettify_line(line: &str, mode: DisplayMode) -> Vec<Segment> {
120	    if mode == DisplayMode::Repr {
121	        return vec![Segment::Plain(line.to_string())];
122	    }
123	
124	    let mut segments = Vec::new();
125	    let mut i = 0;
126	    let bytes = line.as_bytes();
127	    let mut plain_start = 0;
128	
129	    while i < bytes.len() {
130	        // Only try keyword match if we're at a word boundary (start of line or
131	        // preceded by a non-alpha character) AND current char is lowercase alpha.
132	        if bytes[i].is_ascii_lowercase()
133	            && (i == 0 || !bytes[i - 1].is_ascii_alphanumeric())
134	            && let Some((entry, len)) = try_match_keyword(&bytes[i..])
135	        {
136	            // Check the char after the keyword is not alphanumeric (word boundary).
137	            let end = i + len;
138	            if end >= bytes.len() || !bytes[end].is_ascii_alphanumeric() {
139	                // Flush preceding plain text.
140	                if plain_start < i {
141	                    segments.push(Segment::Plain(line[plain_start..i].to_string()));
142	                }
143	                let replacement = match mode {
144	                    DisplayMode::Glyph => entry.glyph.to_string(),
145	                    DisplayMode::Literate => {
146	                        // Dyadic if there's a non-whitespace token before the keyword.
147	                        let is_dyadic = entry.literate_dyadic.is_some()
148	                            && line[..i].contains(|c: char| !c.is_ascii_whitespace());
149	                        if is_dyadic {
150	                            entry.literate_dyadic.unwrap().to_string()
151	                        } else {
152	                            entry.literate_monadic.to_string()
153	                        }
154	                    }
155	                    DisplayMode::Repr => unreachable!(),
156	                };
157	                segments.push(Segment::Keyword(replacement));
158	                i = end;
159	                plain_start = i;
160	                continue;
161	            }
162	        }
163	        i += 1;
164	    }
165	
166	    // Flush remaining plain text.
167	    if plain_start < bytes.len() {
168	        segments.push(Segment::Plain(line[plain_start..].to_string()));
169	    }
170	
171	    segments
172	}
173	
174	fn try_match_keyword(bytes: &[u8]) -> Option<(&'static KeywordEntry, usize)> {
175	    for entry in KEYWORDS {
176	        let kw = entry.ascii.as_bytes();
177	        if bytes.len() >= kw.len() && &bytes[..kw.len()] == kw {
178	            return Some((entry, kw.len()));
179	        }
180	    }
181	    None
182	}
183	
184	/// Literate-name-to-ASCII mapping entry, sorted longest-first for matching.
185	struct LiterateEntry {
186	    literate: &'static str,
187	    ascii: &'static str,
188	}
189	
190	/// Build the literate→ASCII lookup table (longest match first).
191	fn literate_entries() -> Vec<LiterateEntry> {
