            })
            .collect();

        html! {
            <div class="tut-section">
                <h3 class="tut-title">{ title }</h3>
                <p class="tut-desc">{ description }</p>
                <div class="tut-examples">
                    { example_rows }
                </div>
            </div>
        }
    }
}

